+    // ── Edge-case: recipient cursor bounds ────────────────────
+
+    #[test]
+    fn recipient_cursor_stays_at_zero_on_up() {
+        let mut s = state_with_agents(&["A", "B"]);
+        s.active_field = ComposeField::Recipients;
